  ('fire-eq-tech-moex-01396', 'fire-eq-tech', 'fire-eq-tech-moex-108-5f3f518e', 'sub-fire-eq-tech-05', NULL, 'single_choice', '當受熱平面與熱輻射線方向垂直時，其輻射角為0度；兩者平行時，輻射角為90度。假設輻射 源強度不變，當受熱平面由垂直逐漸傾斜，致使輻射角由0度增加至60度時，該平面所受的輻 射熱通量變為原來的若干倍？', '["1/3", "30.5/2", "1/2", "1/20.5"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:21+00:00", "source_pdf_sha1": "0707e0cdd347", "answer_pdf_sha1": "eea7e199dea0", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "502", "s": "0907", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
